window.PACTO.acts["reg-2007-862"]={"label": "REGOLAMENTO (CE) N. 862/2007 DEL PARLAMENTO EUROPEO E DEL CONSIGLIO", "short": "Reg. 862/2007", "file": "ext-reg-2007-862.html", "external": true, "version": "consolidato 2021-07-01", "eurlex": "https://eur-lex.europa.eu/eli/reg/2007/862/oj/ita", "articles": {"1": {"label": "Articolo 1", "heading": "Oggetto", "anchor": "art_1", "frags": [[null, "<p class=\"norm\">Il presente regolamento fissa norme comuni riguardo alla rilevazione di dati e alla compilazione di statistiche comunitarie in materia di:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">immigrazione nei territori degli Stati membri e emigrazione da tali territori, inclusi i flussi tra il territorio di uno Stato membro e quello di un altro Stato membro nonché i flussi tra uno Stato membro e il territorio di un paese terzo;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">cittadinanza e paese di nascita delle persone con dimora abituale nel territorio degli Stati membri;</p>\n</div>\n</div>"], [null, "<p class=\"modref\">\n▼M1\n</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">procedure e procedimenti amministrativi e giudiziari negli Stati membri attinenti all’immigrazione, al rilascio di permessi di residenza, alla cittadinanza, all’asilo e ad altre forme di protezione internazionale, all’ingresso e al soggiorno illegali e ai rimpatri.</p>\n</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"]]}, "2": {"label": "Articolo 2", "heading": "Definizioni", "anchor": "art_2", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Ai fini del presente regolamento si intende per:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«dimora abituale», il luogo in cui una persona trascorre normalmente il periodo quotidiano di riposo a prescindere dalle assenze temporanee a fini ricreativi, di vacanza, visita a parenti e amici, affari e motivi professionali, trattamenti medici o pellegrinaggi religiosi, oppure, in assenza di dati disponibili, il luogo di residenza legale o registrato;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«immigrazione», l’azione con la quale una persona stabilisce la sua dimora abituale nel territorio di uno Stato membro per un periodo minimo di dodici mesi, o che si presume almeno di dodici mesi, dopo aver avuto in precedenza la propria dimora abituale in un altro Stato membro o in un paese terzo;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«emigrazione», l’azione con la quale una persona, dopo aver avuto in precedenza la propria dimora abituale nel territorio di uno Stato membro, cessa di avere la propria dimora abituale in tale Stato membro per un periodo minimo di dodici mesi, o che si presume almeno di dodici mesi;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«cittadinanza», lo specifico vincolo giuridico tra un individuo e lo Stato di appartenenza, acquisito per nascita o naturalizzazione, tramite dichiarazione, opzione, matrimonio o altre modalità, a seconda della legislazione nazionale;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«paese di nascita», il paese di residenza (entro le frontiere attuali, se l'informazione è disponibile) della madre al momento della nascita o, in mancanza, il paese (entro le frontiere attuali, se l'informazione è disponibile) in cui è avvenuta la nascita;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«immigrato», la persona che compie un’azione di immigrazione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«emigrato», la persona che compie un’azione di emigrazione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>h) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«soggiornante di lungo periodo», il soggiornante di lungo periodo quale è definito all’articolo 2, lettera b), della direttiva 2003/109/CE del Consiglio, del 25 novembre 2003, relativa allo status dei cittadini di paesi terzi che siano soggiornanti di lungo periodo (\n<span class=\"superscript\">1</span>\n);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«cittadino di paese terzo», la persona che non è cittadino dell’Unione ai sensi dell’articolo 17, paragrafo 1, del trattato, inclusi gli apolidi;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼M1\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>j) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«domanda di protezione internazionale», una domanda di protezione internazionale quale è definita all’articolo 2, lettera h), della direttiva 2011/95/UE del Parlamento europeo e del Consiglio, del 13 dicembre 2011, recante norme sull’attribuzione, a cittadini di paesi terzi o apolidi, della qualifica di beneficiario di protezione internazionale, su uno status uniforme per i rifugiati o per le persone aventi titolo a beneficiare della protezione sussidiaria, nonché sul contenuto della protezione riconosciuta (\n<span class=\"superscript\">2</span>\n);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>k) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«status di rifugiato», lo status di rifugiato quale è definito all’articolo 2, lettera e), della direttiva 2011/95/UE;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>l) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«status di protezione sussidiaria», lo status di protezione sussidiaria quale è definito all’articolo 2, lettera g), della direttiva 2011/95/UE;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>m) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«familiari», i familiari quali sono definiti all’articolo 2, lettera g), del regolamento (UE) n. 604/2013 del Parlamento europeo e del Consiglio, del 26 giugno 2013, che stabilisce i criteri e i meccanismi di determinazione dello Stato membro competente per l’esame di una domanda di protezione internazionale presentata in uno degli Stati membri da un cittadino di un paese terzo o da un apolide (\n<span class=\"superscript\">3</span>\n);</p>\n</div>\n</div>\n<p class=\"modref\">\n▼B\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>n) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«protezione temporanea», la protezione temporanea quale è definita all’articolo 2, lettera a), della direttiva 2001/55/CE del Consiglio, del 20 luglio 2001, sulle norme minime per la concessione della protezione temporanea in caso di afflusso massiccio di sfollati e sulla promozione dell'equilibrio degli sforzi tra gli Stati membri che ricevono gli sfollati e subiscono le conseguenze dell'accoglienza degli stessi (\n<span class=\"superscript\">4</span>\n);</p>\n</div>\n</div>\n<p class=\"modref\">\n▼M1\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>o) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«minore non accompagnato», un minore non accompagnato quale è definito all’articolo 2, lettera l), della direttiva 2011/95/UE;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>p) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«frontiere esterne», le frontiere esterne quali sono definite all’articolo 2, punto 2), del regolamento (UE) 2016/399 del Parlamento europeo e del Consiglio, del 9 marzo 2016, che istituisce un codice unionale relativo al regime di attraversamento delle frontiere da parte delle persone (codice frontiere Schengen) (\n<span class=\"superscript\">5</span>\n);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>q) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«cittadini di paesi terzi cui è stato rifiutato l’ingresso», i cittadini di paesi terzi cui è stato rifiutato l’ingresso alla frontiera esterna in quanto non soddisfano tutti i requisiti d’ingresso di cui all’articolo 6, paragrafo 1, del regolamento (UE) 2016/399 e non rientrano in nessuna delle categorie di persone di cui all’articolo 6, paragrafo 5, del medesimo regolamento;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼B\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>r) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«cittadini di paesi terzi rintracciati in posizione irregolare», i cittadini di paesi terzi dei quali è stata ufficialmente constatata la presenza sul territorio di uno Stato membro e che non soddisfano, o non soddisfano più, le condizioni di soggiorno o di residenza per quel determinato Stato membro;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>s) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«insediamento», il trasferimento di cittadini di paesi terzi o di apolidi, in base a una valutazione della loro necessità di protezione internazionale e di una soluzione duratura, in uno Stato membro in cui sono autorizzati a risiedere con uno status giuridico sicuro.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Gli Stati membri riferiscono alla Commissione (Eurostat) in merito all'uso e ai probabili effetti delle stime o di altre metodologie di adeguamento delle statistiche basate sulle definizioni nazionali affinché siano conformi alle definizioni armonizzate di cui al paragrafo 1.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M1 —————</p>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Qualora uno Stato membro non sia vincolato al rispetto di uno o più dei testi giuridici citati nelle definizioni di cui al paragrafo 1, tale Stato membro dovrebbe fornire statistiche comparabili a quelle previste ai sensi del presente regolamento, ove ciò sia possibile secondo le vigenti procedure legislative e/o amministrative.</div>\n</div>"]]}, "3": {"label": "Articolo 3", "heading": "Statistiche sulle migrazioni internazionali, sulla popolazione dimorante abitualmente e sull’acquisizione della cittadinanza", "anchor": "art_3", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Gli Stati membri trasmettono alla Commissione (Eurostat) statistiche sul numero di:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">immigrati che si trasferiscono nel territorio dello Stato membro, disaggregate come segue:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">gruppi di cittadinanze per età e sesso;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">gruppi di paesi di nascita per età e sesso;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>iii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">gruppi di paesi di precedente dimora abituale per età e sesso;</p>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">emigrati che si trasferiscono dal territorio dello Stato membro, disaggregate come segue:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">gruppi di cittadinanze;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">età;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>iii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sesso;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>iv) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">gruppi di paesi di successiva dimora abituale;</p>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">persone aventi dimora abituale nello Stato membro alla fine del periodo di riferimento, disaggregate come segue:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">gruppi di cittadinanze per età e sesso;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">gruppi di paesi di nascita per età e sesso;</p>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">persone che hanno dimora abituale nel territorio dello Stato membro e che, durante il periodo di riferimento, hanno acquisito la cittadinanza dello Stato membro dopo aver avuto in precedenza la cittadinanza di un altro Stato membro o di un paese terzo o essere stati nella condizione di apolidi, disaggregate per età, per sesso nonché per precedente cittadinanza o precedente status di apolide delle persone in questione.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Le statistiche di cui al paragrafo 1 riguardano periodi di riferimento di un anno di calendario e sono trasmesse alla Commissione (Eurostat) entro dodici mesi dalla fine dell’anno di riferimento. Il primo anno di riferimento è il 2008.</div>\n</div>"]]}, "4": {"label": "Articolo 4", "heading": "Statistiche sulla protezione internazionale", "anchor": "art_4", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Gli Stati membri trasmettono alla Commissione (Eurostat) statistiche sul numero di:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">persone che hanno presentato domanda di protezione internazionale o sono incluse in tali domande in qualità di familiari durante il periodo di riferimento;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">persone che sono oggetto di domande di protezione internazionale all’esame dell’autorità nazionale responsabile alla fine del periodo di riferimento;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼M1\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">domande di protezione internazionale ritirate durante il periodo di riferimento, disaggregate in base al ritiro esplicito e implicito di cui agli articoli 27 e 28 della direttiva 2013/32/UE del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">6</span>\n);</p>\n</div>\n</div>\n<p class=\"modref\">\n▼M1\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">persone che hanno presentato domanda di protezione internazionale o sono incluse in tali domande in qualità di familiari durante il periodo di riferimento e che chiedono protezione internazionale per la prima volta;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">persone che hanno presentato domanda di protezione internazionale o sono incluse in tali domande in qualità di familiari durante il periodo di riferimento e la cui domanda è stata trattata mediante procedura accelerata di cui all’articolo 31, paragrafo 8, della direttiva 2013/32/UE;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">persone che hanno reiterato la domanda di protezione internazionale a norma dell’articolo 40 della direttiva 2013/32/UE o che sono incluse in tale domanda in qualità di familiari durante il periodo di riferimento;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">persone che hanno presentato domanda di protezione internazionale o sono incluse in tale domanda in qualità di familiari e hanno beneficiato di condizioni materiali di accoglienza che assicurano ai richiedenti un’adeguata qualità di vita ai sensi dell’articolo 17 della direttiva 2013/33/UE del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">7</span>\n), alla fine del periodo di riferimento.</p>\n</div>\n</div>\n<p class=\"modref\">\n▼M1\n</p>\n<p class=\"norm inline-element\">Le statistiche di cui alle lettere da a) a f) sono disaggregate per età e per sesso, per cittadinanza delle persone in questione e per minori non accompagnati. Esse riguardano periodi di riferimento di un mese di calendario e sono trasmesse alla Commissione (Eurostat) entro due mesi dalla fine del mese di riferimento. Il primo mese di riferimento è gennaio 2021.</p>\n<p class=\"norm inline-element\">Le statistiche di cui alla lettera g) riguardano periodi di riferimento di un anno di calendario e sono trasmesse alla Commissione (Eurostat) entro sei mesi dalla fine dell’anno di riferimento. Il primo anno di riferimento è il 2021.</p>\n<p class=\"modref\">\n▼B\n</p>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Gli Stati membri trasmettono alla Commissione (Eurostat) statistiche sul numero di:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">persone interessate da decisioni di primo grado di rigetto di domande di protezione internazionale, quali le decisioni che dichiarano tali domande inammissibili o infondate e quelle adottate in procedimenti d'urgenza o accelerati da organi amministrativi o giudiziari durante il periodo di riferimento;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼M1\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">persone interessate da decisioni di primo grado che riconoscono, revocano o interrompono lo status di rifugiato o ne respingono il rinnovo, adottate da organi amministrativi o giudiziari durante il periodo di riferimento;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">persone interessate da decisioni di primo grado che riconoscono, revocano o interrompono lo status di protezione sussidiaria o ne respingono il rinnovo, adottate da organi amministrativi o giudiziari durante il periodo di riferimento;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼B\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">persone interessate da decisioni di primo grado di concessione o di revoca della protezione temporanea, adottate da organi amministrativi o giudiziari durante il periodo di riferimento;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">persone interessate da altre decisioni di primo grado di concessione o di revoca dell'autorizzazione a soggiornare per motivi umanitari a norma della legislazione nazionale in materia di protezione internazionale, adottate da organi amministrativi o giudiziari durante il periodo di riferimento.</p>\n</div>\n</div>\n<p class=\"modref\">\n▼M1\n</p>\n<p class=\"norm inline-element\">Tali statistiche sono disaggregate per età e per sesso, per cittadinanza delle persone in questione e per minori non accompagnati. Esse riguardano periodi di riferimento di tre mesi di calendario e sono trasmesse alla Commissione (Eurostat) entro due mesi dalla fine del periodo di riferimento. Il primo periodo di riferimento è il trimestre gennaio-marzo 2021.</p>\n<p class=\"modref\">\n▼B\n</p>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Gli Stati membri trasmettono alla Commissione (Eurostat) statistiche sul numero di:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">persone che hanno presentato domanda di protezione internazionale considerate minori non accompagnati dall’autorità nazionale responsabile durante il periodo di riferimento;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">persone interessate da decisioni definitive di rigetto di domande di protezione internazionale, quali le decisioni che dichiarano tali domande inammissibili o infondate, e quelle adottate in procedimenti d'urgenza o accelerati da organi amministrativi o giudiziari in appello o in sede di revisione durante il periodo di riferimento;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼M1\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">persone interessate da decisioni definitive che riconoscono, revocano o interrompono lo status di rifugiato o ne respingono il rinnovo, adottate da organi amministrativi o giudiziari durante il periodo di riferimento;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">persone interessate da decisioni definitive che riconoscono, revocano o interrompono lo status di protezione sussidiaria o ne respingono il rinnovo, adottate da organi amministrativi o giudiziari durante il periodo di riferimento;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼B\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">persone interessate da decisioni definitive di concessione o di revoca della protezione temporanea adottate da organi amministrativi o giudiziari in appello o in sede di revisione durante il periodo di riferimento;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">persone interessate da altre decisioni definitive, adottate da organi amministrativi o giudiziari in appello o in sede di revisione, di concessione o di revoca dell'autorizzazione a soggiornare per motivi umanitari a norma della legislazione nazionale in materia di protezione internazionale, durante il periodo di riferimento;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">persone cui è stata concessa l'autorizzazione a soggiornare in uno Stato membro nel quadro di un programma di reinsediamento nazionale o comunitario durante il periodo di riferimento, ove detto programma sia attuato nello Stato membro in questione.</p>\n</div>\n</div>\n<p class=\"modref\">\n▼M1\n</p>\n<p class=\"norm inline-element\">Tali statistiche sono disaggregate per età e per sesso, per cittadinanza delle persone in questione e, fatta eccezione per la lettera a), per minori non accompagnati. Le statistiche di cui alla lettera g) sono inoltre disaggregate per paese di residenza e per tipo di decisione emessa in relazione alla domanda di asilo.</p>\n<p class=\"norm inline-element\">Le statistiche di cui al primo comma riguardano periodi di riferimento di un anno di calendario e sono trasmesse alla Commissione (Eurostat) entro tre mesi dalla fine dell’anno di riferimento. Il primo anno di riferimento è il 2021.</p>\n<p class=\"modref\">\n▼B\n</p>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Gli Stati membri trasmettono alla Commissione (Eurostat) le seguenti statistiche sull'attuazione del regolamento (CE) n. 343/2003 e del regolamento (CE) n. 1560/2003 della Commissione, del 2 settembre 2003, recante modalità di applicazione del regolamento (CE) n. 343/2003 (\n<span class=\"superscript\">8</span>\n):</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il numero di richieste di ripresa in carico o di presa in carico dei richiedenti asilo;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le norme su cui si fondano le richieste di cui alla lettera a);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le decisioni adottate in esito alle richieste di cui alla lettera a);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il numero di trasferimenti che comportano le decisioni di cui alla lettera c);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il numero di richieste di informazioni;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼M1\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il numero di richieste di riesame relative alla ripresa in carico o alla presa in carico dei richiedenti asilo;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le norme su cui si fondano le richieste di cui alla lettera f);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>h) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le decisioni adottate in esito alle richieste di cui alla lettera f);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il numero di trasferimenti che comportano le decisioni di cui alla lettera h).</p>\n</div>\n</div>\n<p class=\"modref\">\n▼M1\n</p>\n<p class=\"norm inline-element\">Tali statistiche sono disaggregate per sesso e per minori accompagnati e non accompagnati. Esse riguardano periodi di riferimento di un anno di calendario e sono trasmesse alla Commissione (Eurostat) entro tre mesi dalla fine dell’anno di riferimento. Il primo anno di riferimento è il 2021.</p>\n<p class=\"modref\">\n▼B\n</p>\n</div>\n</div>"]]}, "5": {"label": "Articolo 5", "heading": "Statistiche sulla prevenzione dell’ingresso e del soggiorno illegali", "anchor": "art_5", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Gli Stati membri trasmettono alla Commissione (Eurostat) statistiche sul numero di:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">cittadini di paesi terzi cui è stato rifiutato l'ingresso nel territorio dello Stato membro alla frontiera esterna;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">cittadini di paesi terzi rintracciati in posizione irregolare nel territorio dello Stato membro ai sensi della normativa nazionale in materia di immigrazione.</p>\n</div>\n</div>\n<p class=\"modref\">\n▼M1\n</p>\n<p class=\"norm inline-element\">Le statistiche di cui alla lettera a) sono disaggregate ai sensi dell’articolo 14, paragrafo 5, del regolamento (UE) 2016/399.</p>\n<p class=\"norm inline-element\">Le statistiche di cui alla lettera b) sono disaggregate per età e per sesso, per cittadinanza delle persone in questione, per motivi del rintraccio e per luogo del rintraccio.</p>\n<p class=\"modref\">\n▼B\n</p>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Le statistiche di cui al paragrafo 1 riguardano periodi di riferimento di un anno di calendario e sono trasmesse alla Commissione (Eurostat) entro tre mesi dalla fine dell’anno di riferimento. Il primo anno di riferimento è il 2008.</div>\n</div>"]]}, "6": {"label": "Articolo 6", "heading": "Statistiche sui permessi di soggiorno e sul soggiorno di cittadini di paesi terzi", "anchor": "art_6", "frags": [[null, "<p class=\"modref\">\n▼M1\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Gli Stati membri trasmettono alla Commissione (Eurostat) statistiche sul numero di:</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">permessi di soggiorno rilasciati a cittadini di paesi terzi, disaggregati come segue:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">permessi rilasciati durante il periodo di riferimento che consentono al cittadino di paese terzo di soggiornare per la prima volta, disaggregati per cittadinanza, per motivo del rilascio del permesso, per durata della validità del permesso, per età e per sesso;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">permessi rilasciati durante il periodo di riferimento in seguito al cambiamento dello status di immigrazione di un cittadino di paese terzo o del motivo del suo soggiorno, disaggregati per cittadinanza, per motivo del rilascio del permesso, per durata della validità del permesso, per età e per sesso;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>iii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">permessi validi alla fine del periodo di riferimento (numero di permessi rilasciati, non revocati e non scaduti), disaggregati per cittadinanza, per motivo del rilascio del permesso, per durata della validità del permesso, per età e per sesso;</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">soggiornanti di lungo periodo alla fine del periodo di riferimento, disaggregati per cittadinanza, per tipo di status di soggiornante di lungo periodo, per età e per sesso;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">cittadini di paesi terzi che hanno acquisito un permesso di soggiorno di lungo periodo nel corso dell’anno di riferimento, disaggregati per età e per sesso.</p>\n</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Nel caso in cui la normativa nazionale e le prassi amministrative di uno Stato membro consentano la concessione di categorie specifiche di status di immigrazione o di visti a lungo termine in luogo dei permessi di residenza, nelle statistiche di cui al paragrafo 1 sono inclusi i dati relativi a tali visti e a tali riconoscimenti di status.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M1\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Le statistiche di cui al paragrafo 1 riguardano periodi di riferimento di un anno di calendario e sono trasmesse alla Commissione (Eurostat) entro sei mesi dalla fine dell’anno di riferimento. Il primo anno di riferimento è il 2021.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"]]}, "7": {"label": "Articolo 7", "heading": "Statistiche sui rimpatri", "anchor": "art_7", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Gli Stati membri trasmettono alla Commissione (Eurostat) le statistiche concernenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il numero dei cittadini di paesi terzi rintracciati in posizione irregolare nel territorio dello Stato membro e che sono oggetto di una decisione o di un atto amministrativo o giudiziario che ne dichiari illegale il soggiorno e li obblighi a lasciare il territorio dello Stato membro, disaggregato per cittadinanza delle persone interessate;</p>\n</div>\n</div>\n<p class=\"modref\">\n▼M1\n</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il numero dei cittadini di paesi terzi che hanno effettivamente lasciato il territorio dello Stato membro in forza di una decisione o di un atto amministrativo o giudiziario di cui alla lettera a), disaggregato per cittadinanza delle persone rimpatriate, per tipo di rimpatrio, per tipo di assistenza ricevuta e per paese di destinazione.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Le statistiche di cui al paragrafo 1 sono disaggregate per età e per sesso dell’interessato e per minori non accompagnati. Esse riguardano periodi di riferimento di tre mesi di calendario e sono trasmesse alla Commissione (Eurostat) entro due mesi dalla fine del periodo di riferimento. Il primo periodo di riferimento è il trimestre gennaio-marzo 2021.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Le statistiche di cui al paragrafo 1 non includono i cittadini di paesi terzi trasferiti da uno Stato membro all'altro nell'ambito del meccanismo previsto dai regolamenti (CE) n. 343/2003 e (CE) n. 1560/2003.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M1 —————</p>"], [null, "<p class=\"modref\">\n▼B\n</p>"]]}, "9": {"label": "Articolo 9", "heading": "Fonti di dati e standard di qualità", "anchor": "art_9", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Le statistiche si basano sulle seguenti fonti di dati in funzione della loro disponibilità nello Stato membro e conformemente alle normative e alle prassi nazionali:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">registrazioni di azioni amministrative e giudiziarie;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">registri relativi ad azioni amministrative;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">anagrafe della popolazione di persone o di un particolare sottogruppo di tale popolazione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">censimenti;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">indagini campionarie;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">altre fonti appropriate.</p>\n</div>\n</div>\n<p class=\"norm inline-element\">Come parte del processo di elaborazione delle statistiche, possono essere utilizzati metodi di stima scientificamente validi e ben documentati.</p>\n</div>\n</div>"], [null, "<p class=\"modref\">\n▼M1\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">1 bis.  </span>\n<div class=\"norm inline-element\">Gli Stati membri adottano le misure necessarie a garantire la qualità dei dati e dei metadati trasmessi ai sensi del presente regolamento.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">1 ter.  </span>\n<div class=\"norm inline-element\">Si applicano, ai fini del presente regolamento, i criteri di qualità elencati all’articolo 12, paragrafo 1, del regolamento (CE) n. 223/2009 del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">9</span>\n).</div>\n</div>"], [null, "<p class=\"modref\">\n▼M1\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Gli Stati membri informano la Commissione (Eurostat), sotto forma di relazioni sulla qualità, in merito alle fonti di dati utilizzate, ai motivi che hanno condotto alla selezione di tali fonti, agli effetti delle fonti di dati selezionate sulla qualità delle statistiche, alle misure tecniche e organizzative attuate per garantire la protezione dei dati di carattere personale, nonché ai metodi di stima utilizzati, e informano la Commissione (Eurostat) in merito a eventuali cambiamenti.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Su richiesta della Commissione (Eurostat), gli Stati membri trasmettono i chiarimenti supplementari necessari a valutare la qualità delle informazioni statistiche.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Gli Stati membri informano immediatamente la Commissione (Eurostat) in merito a revisioni o correzioni delle statistiche fornite ai sensi del presente regolamento e a qualsiasi cambiamento riguardante i metodi e le fonti di dati utilizzati, e le comunicano senza indugio le pertinenti informazioni o le modifiche inerenti all’esecuzione del presente regolamento che potrebbero influenzare la qualità dei dati trasmessi.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">La Commissione può adottare atti di esecuzione:</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">che specifichino le modalità pratiche e il contenuto delle relazioni sulla qualità di cui al paragrafo 2 del presente articolo;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">relativi alle misure inerenti alla definizione di formati appropriati per la trasmissione di dati ai sensi del presente regolamento.</p>\n</div>\n</div>"], [null, "<p class=\"norm\">Gli atti di cui alla lettera a) non comportano un onere o un costo aggiuntivo considerevole per gli Stati membri.</p>"], [null, "<p class=\"norm\">Gli atti di esecuzione di cui al presente paragrafo sono adottati secondo la procedura d’esame di cui all’articolo 11, paragrafo 2.</p>"], [null, "<p class=\"modref\">\n▼M1\n</p>"]]}, "9a": {"label": "Articolo 9 bis", "heading": "Studi pilota", "anchor": "art_9a", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">In conformità degli obiettivi del presente regolamento, la Commissione (Eurostat) istituisce studi pilota, che saranno svolti dagli Stati membri su base volontaria, al fine di sottoporre a prova la fattibilità di nuove rilevazioni o disaggregazioni di dati nell’ambito di applicazione del presente regolamento, tra cui la disponibilità di fonti di dati e tecniche di produzione adeguate, la qualità e la comparabilità delle statistiche e i costi e gli oneri che ne derivano. Gli Stati membri, insieme alla Commissione (Eurostat), garantiscono la rappresentatività a livello di Unione di tali studi pilota.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Prima di avviare uno studio pilota specifico, la Commissione (Eurostat) valuta se le nuove statistiche possano essere basate sulle informazioni disponibili nelle pertinenti fonti amministrative a livello di Unione al fine di armonizzare, ove possibile, i concetti utilizzati e di ridurre al minimo gli oneri aggiuntivi per gli istituti nazionali di statistica e le altre autorità nazionali e migliorare l’uso dei dati esistenti in conformità dell’articolo 17 <span class=\"italics\">bis</span> del regolamento (CE) n. 223/2009. La Commissione (Eurostat) tiene conto anche dell’onere derivante da altri studi pilota in corso al fine di limitare il numero di studi pilota concomitanti durante lo stesso periodo di tempo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Gli studi pilota di cui al presente articolo riguardano:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per le statistiche di cui all’articolo 4 nel suo insieme: disaggregazioni per mese di presentazione della domanda di protezione internazionale;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per le statistiche di cui all’articolo 4, paragrafo 1:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il numero di persone che hanno presentato domanda di protezione internazionale o sono incluse in tali domande in qualità di familiari e che:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>— </span>\n</div>\n<div class=\"grid-list-column-2\">\n<div class=\"list\">sono state esentate da una procedura accelerata o da una procedura di frontiera o la cui domanda di protezione internazionale è stata trattata mediante tale procedura di frontiera;</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>— </span>\n</div>\n<div class=\"grid-list-column-2\">\n<div class=\"list\">non sono registrate nell’Eurodac;</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>— </span>\n</div>\n<div class=\"grid-list-column-2\">\n<div class=\"list\">hanno presentato prove documentali che potrebbero contribuire all’accertamento della loro identità;</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>— </span>\n</div>\n<div class=\"grid-list-column-2\">\n<div class=\"list\">si trovavano in stato di trattenimento, disaggregate per durata del trattenimento e per motivo del trattenimento o erano oggetto di decisioni o atti amministrativi o giudiziari che ne ordinavano il trattenimento o un’alternativa al trattenimento, disaggregate per tipo di alternativa e per il mese di emissione di tale decisione o atto;</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>— </span>\n</div>\n<div class=\"grid-list-column-2\">\n<div class=\"list\">hanno beneficiato dell’assistenza legale gratuita;</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>— </span>\n</div>\n<div class=\"grid-list-column-2\">\n<div class=\"list\">hanno beneficiato delle condizioni materiali di accoglienza di cui all’articolo 4, paragrafo 1, lettera g), disaggregate per età, per sesso, per cittadinanza e per minori non accompagnati, compresa la possibilità di mettere in relazione tali statistiche con periodi di riferimento di un mese;</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>— </span>\n</div>\n<div class=\"grid-list-column-2\">\n<div class=\"list\">erano minori non accompagnati a cui è stato nominato un rappresentante, minori non accompagnati a cui è stato consentito di accedere al sistema educativo o minori non accompagnati a cui è stato offerto un alloggio in conformità dell’articolo 31, paragrafo 3, della direttiva 2011/95/UE;</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>— </span>\n</div>\n<div class=\"grid-list-column-2\">\n<div class=\"list\">sono state sottoposte ad accertamento dell’età, compresi i risultati di tali accertamenti;</div>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">numero medio di minori non accompagnati che hanno presentato domanda di protezione internazionale per rappresentante;</p>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per le statistiche di cui all’articolo 4, paragrafi 2 e 3:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per le persone rientranti nell’ambito di applicazione dell’articolo 4, paragrafo 2, lettera a), o dell’articolo 4, paragrafo 3, lettera b), disaggregazioni per decisioni di rigetto delle domande di protezione internazionale:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>— </span>\n</div>\n<div class=\"grid-list-column-2\">\n<div class=\"list\">in quanto inammissibili, in base ai motivi per l’inammissibilità;</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>— </span>\n</div>\n<div class=\"grid-list-column-2\">\n<div class=\"list\">in quanto infondate;</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>— </span>\n</div>\n<div class=\"grid-list-column-2\">\n<div class=\"list\">in quanto manifestamente infondate nell’ambito di un procedimento ordinario, in base ai motivi del rigetto;</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>— </span>\n</div>\n<div class=\"grid-list-column-2\">\n<div class=\"list\">in quanto manifestamente infondate nell’ambito di un procedimento accelerato, in base ai motivi del rigetto e del procedimento accelerato;</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>— </span>\n</div>\n<div class=\"grid-list-column-2\">\n<div class=\"list\">in quanto il richiedente può beneficiare di protezione all’interno del paese di origine;</div>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per le persone rientranti nell’ambito di applicazione dell’articolo 4, paragrafo 2, lettere b) e c), e dell’articolo 4, paragrafo 3, lettere c) e d), disaggregazioni per decisioni in merito alla cessazione o all’esclusione, ulteriormente disaggregate per motivo di cessazione o esclusione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>iii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il numero di persone interessate da decisioni adottate a seguito di un colloquio personale;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>iv) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il numero di persone interessate da decisioni di primo grado o da decisioni definitive che riducono o revocano le condizioni materiali di accoglienza;</p>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per le statistiche di cui all’articolo 4, paragrafo 3, la durata dei ricorsi;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per le statistiche di cui all’articolo 4, paragrafo 4, disaggregazioni per età e per cittadinanza;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per le statistiche di cui all’articolo 6, il numero di:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">domande, comprese quelle respinte, di permesso di soggiorno presentate per la prima volta da cittadini di paesi terzi durante il periodo di riferimento, disaggregate per cittadinanza, per motivo della richiesta del permesso, per età e per sesso;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">domande respinte di permesso di soggiorno in seguito al cambiamento dello status di immigrazione di un cittadino di paese terzo o del motivo del suo soggiorno;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>iii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">permessi di soggiorno rilasciati per motivi familiari, disaggregati per motivo del rilascio del permesso e per status del richiedente il ricongiungimento del cittadino di paese terzo;</p>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per le statistiche di cui all’articolo 7, disaggregazioni per:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i motivi delle decisioni o degli atti di cui al paragrafo 1, lettera a), di tale articolo;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il numero di persone di cui al paragrafo 1, lettera a), di tale articolo soggette a un divieto d’ingresso;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>iii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il numero di persone in procedure di rimpatrio soggette a decisione o atto amministrativo o giudiziario che ne disponga il trattenimento, disaggregate ulteriormente per durata del trattenimento, o soggette a un’alternativa al trattenimento, disaggregate per tipo di alternativa e mese di emissione di tale decisione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>iv) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il numero di persone rimpatriate, ulteriormente disaggregate per paese di destinazione e per tipo di decisione o atto come segue:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>— </span>\n</div>\n<div class=\"grid-list-column-2\">\n<div class=\"list\">in forza di un accordo formale di riammissione dell’Unione;</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>— </span>\n</div>\n<div class=\"grid-list-column-2\">\n<div class=\"list\">in forza di un accordo informale di riammissione dell’Unione;</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>— </span>\n</div>\n<div class=\"grid-list-column-2\">\n<div class=\"list\">in forza di un accordo di riammissione nazionale.</div>\n</div>\n</div>\n</div>\n</div>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">La Commissione (Eurostat) valuta, in stretta cooperazione con gli Stati membri, i risultati degli studi pilota e li rende pubblici. La valutazione comprende una stima del valore aggiunto delle nuove rilevazioni di dati nell’ambito degli studi pilota a livello di Unione e un’analisi dell’efficacia in termini di costi, compresa una valutazione dell’onere per i rispondenti e dei costi di produzione a norma dell’articolo 14, paragrafo 3, del regolamento (CE) n. 223/2009.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Tenendo conto della valutazione positiva dei risultati degli studi pilota, la Commissione può adottare atti di esecuzione riguardo alle questioni di cui al paragrafo 3. Tali atti di esecuzione sono adottati secondo la procedura d’esame di cui all’articolo 11, paragrafo 2.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Al fine di agevolare la realizzazione degli studi pilota di cui al presente articolo, la Commissione (Eurostat) fornisce finanziamenti adeguati conformemente all’articolo 9 <span class=\"italics\">ter</span> agli Stati membri che effettuano tali studi pilota.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">Entro il 13 luglio 2022, e successivamente ogni due anni, la Commissione (Eurostat) presenta una relazione sui progressi complessivi compiuti riguardo alle questioni di cui al paragrafo 3. La relazione è resa pubblica.</div>\n</div>"]]}, "9b": {"label": "Articolo 9 ter", "heading": "Finanziamento", "anchor": "art_9b", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Ai fini dell’attuazione del presente regolamento i contributi finanziari sono forniti a titolo del bilancio generale dell’Unione agli istituti nazionali di statistica e alle altre autorità nazionali interessate di cui all’articolo 5, paragrafo 2, del regolamento (CE) n. 223/2009, per:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">lo sviluppo di nuove metodologie per le statistiche ai sensi del presente regolamento, compresa la partecipazione degli Stati membri agli studi pilota di cui all’articolo 9 <span class=\"italics\">bis</span>;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">lo sviluppo o l’attuazione di nuove rilevazioni e disaggregazioni di dati nell’ambito di applicazione del presente regolamento, compreso l’aggiornamento delle fonti di dati e dei sistemi informatici, per un periodo massimo di cinque anni.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">I contributi finanziari dell’Unione di cui al paragrafo 1 del presente articolo sono forniti in conformità del regolamento (UE, Euratom) 2018/1046 del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">10</span>\n).</div>\n</div>"], [null, "<p class=\"modref\">\n▼M1\n</p>"]]}, "10": {"label": "Articolo 10", "heading": "Atti di esecuzione al fine di specificare le disaggregazioni", "anchor": "art_10", "frags": [[null, "<p class=\"norm\">Alla Commissione è conferito il potere di adottare atti di esecuzione al fine di specificare le disaggregazioni conformemente agli articoli da 4 a 7. Quando adotta tali atti di esecuzione, la Commissione giustifica la necessità delle disaggregazioni interessate ai fini dello sviluppo e del monitoraggio delle politiche dell’Unione in materia di migrazione e asilo e assicura che detti atti di esecuzione non comportino considerevoli costi o oneri aggiuntivi per gli Stati membri.</p>"], [null, "<p class=\"norm\">Tali atti di esecuzione sono adottati secondo la procedura d’esame di cui all’articolo 11, paragrafo 2, al più tardi 18 mesi prima della fine del periodo di riferimento quando i dati si riferiscono a un anno civile, e al più tardi 6 mesi prima della fine del periodo di riferimento quando i dati si riferiscono a un periodo inferiore a un anno.</p>"]]}, "11": {"label": "Articolo 11", "heading": "Procedura di comitato", "anchor": "art_11", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">La Commissione è assistita dal comitato del sistema statistico europeo istituito dal regolamento (CE) n. 223/2009. Esso è un comitato ai sensi del regolamento (UE) n. 182/2011 del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">11</span>\n).</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Nei casi in cui è fatto riferimento al presente paragrafo, si applica l’articolo 5 del regolamento (UE) n. 182/2011.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M1\n</p>"]]}, "11a": {"label": "Articolo 11 bis", "heading": "Deroghe", "anchor": "art_11a", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Ove l’applicazione del presente regolamento, o degli atti di esecuzione adottati a norma dello stesso, richieda adeguamenti significativi del sistema statistico nazionale di uno Stato membro, la Commissione può concedere, mediante atti di esecuzione, una deroga per il periodo di tempo richiesto dallo Stato membro interessato, purché tale periodo non superi i tre anni. In tal caso, la Commissione garantisce la comparabilità dei dati degli Stati membri e il calcolo tempestivo degli aggregati europei rappresentativi e affidabili richiesti e tiene conto dell’onere a carico degli Stati membri e dei rispondenti.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Nel caso in cui una deroga di cui al paragrafo 1 sia ancora giustificata da prove sufficienti alla fine del periodo per il quale è stata concessa, la Commissione può concedere, mediante atti di esecuzione, una deroga per un ulteriore periodo richiesto dallo Stato membro interessato, purché tale periodo non superi i due anni.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Ai fini dei paragrafi 1 e 2, lo Stato membro presenta alla Commissione una richiesta debitamente motivata, a seconda dei casi, entro il 13 ottobre 2020 o entro tre mesi dalla data di entrata in vigore dell’atto di esecuzione in questione o sei mesi prima della scadenza del periodo per il quale è stata concessa la deroga corrente.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Tali atti di esecuzione sono adottati secondo la procedura d’esame di cui all’articolo 11, paragrafo 2.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"]]}, "12": {"label": "Articolo 12", "heading": "Relazione", "anchor": "art_12", "frags": [[null, "<p class=\"norm\">Entro il 20 agosto 2012 e, successivamente, ogni tre anni, la Commissione trasmette al Parlamento europeo e al Consiglio una relazione in merito alle statistiche compilate a norma del presente regolamento e alla loro qualità.</p>"]]}, "13": {"label": "Articolo 13", "heading": "Abrogazione", "anchor": "art_13", "frags": [[null, "<p class=\"norm\">Il regolamento (CEE) n. 311/76 è abrogato.</p>"]]}, "14": {"label": "Articolo 14", "heading": "Entrata in vigore", "anchor": "art_14", "frags": [[null, "<p class=\"norm\">Il presente regolamento entra in vigore il ventesimo giorno successivo alla pubblicazione nella <span class=\"italics\">Gazzetta ufficiale dell’Unione europea</span>.</p>"], [null, "<p class=\"norm\">Il presente regolamento è obbligatorio in tutti i suoi elementi e direttamente applicabile in ciascuno degli Stati membri.</p>"], [null, "<p>\n<br/>\n</p>"], [null, "<p class=\"footnote\">(\n<span class=\"superscript\">1</span>\n) GU L 16 del 23.1.2004, pag. 44.</p>"], [null, "<p class=\"footnote\">(\n<span class=\"superscript\">2</span>\n) GU L 337 del 20.12.2011, pag. 9.</p>"], [null, "<p class=\"footnote\">(\n<span class=\"superscript\">3</span>\n) GU L 180 del 29.6.2013, pag. 31.</p>"], [null, "<p class=\"footnote\">(\n<span class=\"superscript\">4</span>\n) GU L 212 del 7.8.2001, pag. 12.</p>"], [null, "<p class=\"footnote\">(\n<span class=\"superscript\">5</span>\n) GU L 77 del 23.3.2016, pag. 1</p>"], [null, "<p class=\"footnote\">(\n<span class=\"superscript\">6</span>\n) Direttiva 2013/32/UE del Parlamento europeo e del Consiglio, del 26 giugno 2013, recante procedure comuni ai fini del riconoscimento e della revoca dello status di protezione internazionale (GU L 180 del 29.6.2013, pag. 60).</p>"], [null, "<p class=\"footnote\">(\n<span class=\"superscript\">7</span>\n) Direttiva 2013/33/UE del Parlamento europeo e del Consiglio, del 26 giugno 2013, recante norme relative all’accoglienza dei richiedenti protezione internazionale (GU L 180 del 29.6.2013, pag. 96).</p>"], [null, "<p class=\"footnote\">(\n<span class=\"superscript\">8</span>\n) GU L 222 del 5.9.2003, pag. 3.</p>"], [null, "<p class=\"footnote\">(\n<span class=\"superscript\">9</span>\n) Regolamento (CE) n. 223/2009 del Parlamento europeo e del Consiglio, dell’11 marzo 2009, relativo alle statistiche europee e che abroga il regolamento (CE, Euratom) n. 1101/2008 del Parlamento europeo e del Consiglio, relativo alla trasmissione all’Istituto statistico delle Comunità europee di dati statistici protetti dal segreto, il regolamento (CE) n. 322/97 del Consiglio, relativo alle statistiche comunitarie, e la decisione 89/382/CEE, Euratom del Consiglio, che istituisce un comitato del programma statistico delle Comunità europee (GU L 87 del 31.3.2009, pag. 164).</p>"], [null, "<p class=\"footnote\">(\n<span class=\"superscript\">10</span>\n) Regolamento (UE, Euratom) 2018/1046 del Parlamento europeo e del Consiglio, del 18 luglio 2018, che stabilisce le regole finanziarie applicabili al bilancio generale dell’Unione, che modifica i regolamenti (UE) n. 1296/2013, (UE) n. 1301/2013, (UE) n. 1303/2013, (UE) n. 1304/2013, (UE) n. 1309/2013, (UE) n. 1316/2013, (UE) n. 223/2014, (UE) n. 283/2014 e la decisione n. 541/2014/UE e abroga il regolamento (UE, Euratom) n. 966/2012 (GU L 193 del 30.7.2018, pag. 1).</p>"], [null, "<p class=\"footnote\">(\n<span class=\"superscript\">11</span>\n) Regolamento (UE) n. 182/2011 del Parlamento europeo e del Consiglio, del 16 febbraio 2011, che stabilisce le regole e i principi generali relativi alle modalità di controllo da parte degli Stati membri dell’esercizio delle competenze di esecuzione attribuite alla Commissione (GU L 55 del 28.2.2011, pag. 13).</p>"]]}}, "recitals": {}};